                        to,
                        amount.sub(1),
                        force
                    ); // T:[CM-14, 17, 22, 23]

                    // SWC-101-Integer Overflow and Underflow: L594 - L595
                    totalValue += tv;
                    totalWeightedValue += tvw;
                } // Michael Egorov gas efficiency trick
            }
        }
    }

